import { app } from './src/server.js';
import http from 'http';
import fs from 'fs';
const logFile = 'D:/Bolt-On/Executive_Summary/node-backend/test-api.log';
fs.writeFileSync\(logFile, 'starting\\n'\);
try {
  const server = app.listen\(9879, '127.0.0.1', \(\) => { 
    fs.appendFileSync\(logFile, 'server up\\n'\);
    const req = http.get\('http://127.0.0.1:9879/api/v1/campaigns', \(res\) => {
      let d = '';
      res.on\('data', c => d += c\);
      res.on\('end', \(\) => {
        fs.appendFileSync\(logFile, 'status=' + res.statusCode + '\\nbody=' + d.slice\(0, 400\) + '\\n'\);
