      }\);
    }\);
    req.on\('error', e => { fs.appendFileSync\(logFile, 'err=' + e.message + '\\n'\); process.exit\(1\); }\);
  }\);
} catch\(e\) {
  fs.appendFileSync\(logFile, 'catch=' + e.message + '\\n'\);
  process.exit\(1\);
